sys_script_client.script:
function onLoad() {
	if ((g_form.getDisplayValue('tasker_type')  == 'Information Only') &&
		(g_form.getValue('assigned_to')  == g_user.userID))	{

		var set_state = new GlideAjax("ClientTaskInfo");
		set_state.addParam('sysparm_name', 'updateTaskStateToComplete');
		set_state.addParam('sysparm_sysId', g_form.getUniqueValue());
		set_state.getXML(setState);

		function setState(response){
			var stateFromScriptInclude = response.responseXML.documentElement.getAttribute("answer");					
		}
	}
}
